def remove_character_case_insensitive(input_string: str, char_to_remove: str) -> dict:
    """Removes all occurrences of a specified character from a string, treating the character to be removed in a case-insensitive manner.

    Args:
        input_string (str): The original string from which characters will be removed.
        char_to_remove (str): The single character to be removed from the input string. Comparisons are case-insensitive.

    Returns:
        dict: A dictionary containing the status and the modified string if successful.
              On error, returns 'status': 'error' and 'error_message': '...'
              Success keys: 'status', 'modified_string'.
    """
    if not isinstance(input_string, str):
        return {"status": "error", "error_message": "Input 'input_string' must be a string."}
    if not isinstance(char_to_remove, str):
        return {"status": "error", "error_message": "Input 'char_to_remove' must be a string."}
    if len(char_to_remove) != 1:
        return {"status": "error", "error_message": "Input 'char_to_remove' must be a single character."}

    # Convert the character to remove to lowercase for case-insensitive comparison
    lower_char_to_remove = char_to_remove.lower()

    # Build the new string by including only characters that are not the one to be removed (case-insensitive)
    modified_chars = []
    for char in input_string:
        if char.lower() != lower_char_to_remove:
            modified_chars.append(char)

    modified_string = "".join(modified_chars)

    return {
        "status": "success",
        "modified_string": modified_string
    }
